const items = $input.all();

// Separate income and expenses
const expenses = items.filter(i => i.json.Type === 'Expense');
const income = items.filter(i => i.json.Type === 'Income');

// Calculate totals
const totalExpenses = expenses.reduce((sum, i) => sum + i.json.Amount, 0);
const totalIncome = income.reduce((sum, i) => sum + i.json.Amount, 0);
const netBalance = totalIncome - totalExpenses;

// Calculate average expense
const avgExpense = totalExpenses / expenses.length;

// Detect anomalies
const anomalies = [];

// Check for unusually large expenses (3x average)
expenses.forEach(i => {
  if (i.json.Amount > avgExpense * 3) {
    anomalies.push({
      type: 'Large Expense',
      description: i.json.Description,
      amount: i.json.Amount,
      date: i.json.Date,
    });
  }
});

// Check for duplicate charges
const descriptions = {};
expenses.forEach(i => {
  const key = `${i.json.Description}-${i.json.Amount}`;
  if (descriptions[key]) {
    anomalies.push({
      type: 'Duplicate Charge',
      description: i.json.Description,
      amount: i.json.Amount,
      date: i.json.Date,
    });
  }
  descriptions[key] = true;
});

// Category breakdown
const categories = {};
expenses.forEach(i => {
  categories[i.json.Category] = (categories[i.json.Category] || 0) + i.json.Amount;
});

return [{
  json: {
    totalIncome,
    totalExpenses,
    netBalance,
    avgExpense: avgExpense.toFixed(2),
    anomaliesFound: anomalies.length > 0,
    anomalies,
    categories,
    transactionCount: items.length,
    reportDate: new Date().toDateString(),
  }
}];

