const aiOutput = $input.first().json.output?.[0]?.content?.[0]?.text || "";
const original = $('Analyze Spending').first().json;

const healthMatch = aiOutput.match(/\*?\*?FinancialHealth:\*?\*?\s*(.+)/);
const subjectMatch = aiOutput.match(/\*?\*?Subject:\*?\*?\s*(.+)/);
const reportMatch = aiOutput.match(/\*?\*?Subject:.+\n+([\s\S]+)/);

const health = healthMatch ? healthMatch[1].replace(/\*/g, '').trim() : "Warning";
const subject = subjectMatch ? subjectMatch[1].replace(/\*/g, '').trim() : "Financial Report";

return [{
  json: {
    totalIncome: original.totalIncome,
    totalExpenses: original.totalExpenses,
    netBalance: original.netBalance,
    anomaliesFound: original.anomaliesFound,
    anomalies: original.anomalies,
    categories: original.categories,
    reportDate: original.reportDate,
    financialHealth: health,
    subject: subject,
    report: reportMatch ? reportMatch[1].trim() : "",
    isAnomaly: original.anomaliesFound,
  }
}];

